import{_ as t,c as e,o as r,ag as l}from"./chunks/framework.dvv-DFtf.js";const c=JSON.parse('{"title":"Webmail — 企业邮件平台","description":"","frontmatter":{},"headers":[],"relativePath":"webmail/index.md","filePath":"webmail/index.md","lastUpdated":null}'),d={name:"webmail/index.md"};function i(o,a,n,h,s,u){return r(),e("div",null,[...a[0]||(a[0]=[l('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /webmail.md for this page in Markdown format</div><h1 id="webmail-—-企业邮件平台" tabindex="-1">Webmail — 企业邮件平台 <a class="header-anchor" href="#webmail-—-企业邮件平台" aria-label="Permalink to &quot;Webmail — 企业邮件平台&quot;">​</a></h1><h2 id="什么是-lurus-webmail" tabindex="-1">什么是 Lurus Webmail？ <a class="header-anchor" href="#什么是-lurus-webmail" aria-label="Permalink to &quot;什么是 Lurus Webmail？&quot;">​</a></h2><p><strong>Lurus Webmail</strong> 是基于 Stalwart Mail Server 的自建企业邮件系统，前端使用 Next.js，后端使用 Nitro 处理 IMAP/SMTP 同步。</p><ul><li><strong>Web 访问</strong>：<a href="https://mail.lurus.cn" target="_blank" rel="noreferrer">mail.lurus.cn</a></li><li><strong>邮件域</strong>：<code>@lurus.cn</code></li><li><strong>特点</strong>：针对中国网络环境优化送达率，QQ / 网易 / 阿里邮箱送达率 ≥ 99%</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="📧-完整邮件协议支持" tabindex="-1">📧 完整邮件协议支持 <a class="header-anchor" href="#📧-完整邮件协议支持" aria-label="Permalink to &quot;📧 完整邮件协议支持&quot;">​</a></h3><table tabindex="0"><thead><tr><th>协议</th><th>端口</th><th>加密</th><th>用途</th></tr></thead><tbody><tr><td>IMAP</td><td>993</td><td>SSL/TLS</td><td>收取邮件</td></tr><tr><td>SMTP</td><td>465</td><td>SSL/TLS</td><td>发送邮件</td></tr><tr><td>SMTP</td><td>587</td><td>STARTTLS</td><td>提交邮件（推荐）</td></tr><tr><td>ManageSieve</td><td>4190</td><td>STARTTLS</td><td>邮件过滤规则</td></tr></tbody></table><h3 id="📅-日历与联系人-caldav-carddav" tabindex="-1">📅 日历与联系人（CalDAV / CardDAV） <a class="header-anchor" href="#📅-日历与联系人-caldav-carddav" aria-label="Permalink to &quot;📅 日历与联系人（CalDAV / CardDAV）&quot;">​</a></h3><ul><li>日历同步（CalDAV）：集成 Apple Calendar、Thunderbird、GNOME Calendar</li><li>联系人同步（CardDAV）：集成 Apple Contacts、各平台通讯录</li></ul><h3 id="🛡️-邮件安全" tabindex="-1">🛡️ 邮件安全 <a class="header-anchor" href="#🛡️-邮件安全" aria-label="Permalink to &quot;🛡️ 邮件安全&quot;">​</a></h3><ul><li><strong>SPF / DKIM / DMARC</strong> 全配置，防止邮件伪造</li><li><strong>TLS 端到端加密</strong>传输</li><li><strong>反垃圾邮件</strong>：Rspamd 引擎过滤</li></ul><h3 id="🌏-中国送达率优化" tabindex="-1">🌏 中国送达率优化 <a class="header-anchor" href="#🌏-中国送达率优化" aria-label="Permalink to &quot;🌏 中国送达率优化&quot;">​</a></h3><ul><li>国内主流域名（QQ、网易、阿里）通过 <strong>SendCloud</strong> 中继发送</li><li>国际邮件通过 Stalwart 直接发送</li></ul><h2 id="用户类型" tabindex="-1">用户类型 <a class="header-anchor" href="#用户类型" aria-label="Permalink to &quot;用户类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用户类型</th><th>说明</th></tr></thead><tbody><tr><td>企业员工</td><td>使用 <code>username@lurus.cn</code> 地址收发邮件</td></tr><tr><td>管理员</td><td>管理账号、域名、别名、配额</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/webmail/quickstart">快速开始</a> — 首次登录和发送第一封邮件</li><li><a href="/webmail/client-setup">客户端配置</a> — 配置 Outlook、Apple Mail、Thunderbird</li><li><a href="/webmail/faq">常见问题</a> — 送达问题、密码重置等</li></ul>',18)])])}const m=t(d,[["render",i]]);export{c as __pageData,m as default};
